  useEffect(() => {
    getTasks()
  }, [])

  const getTasks = async () => {
    const response = await axios.get('http://localhost:3000/tasks')
    setTasks(response.data)
  }

  return (
    <div>
      {tasks.map(task => (
        <div key={task.id}>
          <input type="checkbox" checked={task.is_complete} />
          <label>{task.title}</label>
        </div>
      ))}
    </div>
  )
}

